import React, { useState, useEffect } from 'react';

import { getSuggestions } from '../services/api';

function OptimizationTips() {

  const [tips, setTips] = useState([]);

  useEffect(() => {

    const fetchTips = async () => {

      try {

        const response = await getSuggestions();

        setTips(response.data);

      } catch (error) {

        console.error('Error fetching suggestions:', error);

      }

    };

    fetchTips();

  }, []);

  return (
    <div>
      <h2 className="tips-title">Optimization Tips</h2>
      <ul style={{ listStyle: 'none', padding: 0 }}>
        {tips.map((tip, index) => (
          <li key={index} style={{ marginBottom: '10px', padding: '10px', background: 'rgba(255,255,255,0.05)', borderRadius: '10px' }}>
            💡 {tip}
          </li>
        ))}
      </ul>
    </div>
  );
}

export default OptimizationTips;
